package com.assetflow.nexora.entity;
import jakarta.persistence.*; import java.time.*; @Entity @Table(name="asset_documents") public class AssetDocument { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="document_id") public Long id; @Column(name="asset_id",nullable=false) public Long assetId; @Column(name="file_url",nullable=false,length=500) public String fileUrl; @Column(name="file_type",length=50) public String fileType; @Column(name="uploaded_by",nullable=false) public Long uploadedBy; @Column(name="uploaded_at",nullable=false) public OffsetDateTime uploadedAt; @PrePersist void created(){if(uploadedAt==null)uploadedAt=OffsetDateTime.now(ZoneOffset.UTC);} }
